namespace DocSummary.Models;

public class SummarizeRequest
{
    public required string DocumentText { get; set; }
    public int MaxSentences { get; set; } = 3;
}

namespace DocSummary.Models;

public class SummarizeResponse
{
    public required string Summary { get; set; }
    public int OriginalLength { get; set; }
    public int SummaryLength { get; set; }
}

namespace DocSummary.Services;

public interface ISummarizationService
{
    string Summarize(string documentText, int maxSentences);
}

namespace DocSummary.Services;

/// <summary>
/// Extractive summarization that scores sentences by word frequency
/// and returns the top-ranked sentences in their original order.
/// </summary>
public class ExtractiveSummarizationService : ISummarizationService
{
    private static readonly char[] SentenceDelimiters = ['.', '!', '?'];

    public string Summarize(string documentText, int maxSentences)
    {
        if (string.IsNullOrWhiteSpace(documentText))
            return string.Empty;

        var sentences = SplitIntoSentences(documentText);

        if (sentences.Count <= maxSentences)
            return string.Join(" ", sentences);

        var wordFrequencies = ComputeWordFrequencies(sentences);
        var scored = sentences
            .Select((sentence, index) => (Sentence: sentence, Index: index, Score: ScoreSentence(sentence, wordFrequencies)))
            .OrderByDescending(s => s.Score)
            .Take(maxSentences)
            .OrderBy(s => s.Index)
            .Select(s => s.Sentence);

        return string.Join(" ", scored);
    }

    private static List<string> SplitIntoSentences(string text)
    {
        var sentences = new List<string>();
        int start = 0;

        for (int i = 0; i < text.Length; i++)
        {
            if (SentenceDelimiters.Contains(text[i]))
            {
                var sentence = text[start..(i + 1)].Trim();
                if (sentence.Length > 0)
                    sentences.Add(sentence);
                start = i + 1;
            }
        }

        // Handle trailing text without a sentence delimiter
        if (start < text.Length)
        {
            var remaining = text[start..].Trim();
            if (remaining.Length > 0)
                sentences.Add(remaining);
        }

        return sentences;
    }

    private static Dictionary<string, int> ComputeWordFrequencies(List<string> sentences)
    {
        var frequencies = new Dictionary<string, int>(StringComparer.OrdinalIgnoreCase);

        foreach (var sentence in sentences)
        {
            foreach (var word in GetWords(sentence))
            {
                frequencies.TryGetValue(word, out int count);
                frequencies[word] = count + 1;
            }
        }

        return frequencies;
    }

    private static double ScoreSentence(string sentence, Dictionary<string, int> wordFrequencies)
    {
        var words = GetWords(sentence);
        if (words.Length == 0)
            return 0;

        double total = words.Sum(w => wordFrequencies.GetValueOrDefault(w, 0));
        return total / words.Length;
    }

    private static string[] GetWords(string text)
    {
        return text.Split([' ', '\t', '\n', '\r', ',', ';', ':', '"', '\'', '(', ')', '[', ']', '{', '}'],
            StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries);
    }
}

using DocSummary.Models;
using DocSummary.Services;
using Microsoft.AspNetCore.Mvc;

namespace DocSummary.Controllers;

[ApiController]
[Route("api/[controller]")]
public class SummarizeController : ControllerBase
{
    private readonly ISummarizationService _summarizationService;

    public SummarizeController(ISummarizationService summarizationService)
    {
        _summarizationService = summarizationService;
    }

    [HttpPost]
    public IActionResult Summarize([FromBody] SummarizeRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.DocumentText))
            return BadRequest(new { error = "DocumentText must not be empty." });

        if (request.MaxSentences < 1)
            return BadRequest(new { error = "MaxSentences must be at least 1." });

        var summary = _summarizationService.Summarize(request.DocumentText, request.MaxSentences);

        return Ok(new SummarizeResponse
        {
            Summary = summary,
            OriginalLength = request.DocumentText.Length,
            SummaryLength = summary.Length
        });
    }
}

